	result := L.Get(-1)
	L.Pop(1) // Clean up the stack by removing the result

	// Validate the result is a number
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	// Convert Lua number to Go float64 and return
	return float64(result.(lua.LNumber)), nil
