package main

import (
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

const (
	// memoryLimit is the maximum amount of memory the Lua script can use (10MB)
	memoryLimit = 10 * 1024 * 1024
	// executionTimeout is the maximum time allowed for the entire script execution (loading + function call)
	executionTimeout = time.Second
	// recursionLimit is the maximum allowed function call depth
	recursionLimit = 100
	// hookInstructionCount is the number of instructions between timeout checks
	hookInstructionCount = 10000
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a sandboxed Lua state with memory limit
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true,
		MemoryLimit:  memoryLimit,
	})
	defer L.Close()

	startTime := time.Now()
	callDepth := 0

	// Set a debug hook to handle timeout, recursion limit, and instruction counting
	L.SetHook(func(L *lua.LState, dbg *lua.Debug) int {
		switch dbg.Event {
		case lua.HookCount:
			// Check for execution timeout
			if time.Since(startTime) > executionTimeout {
				L.RaiseError("script execution timed out after %v", executionTimeout)
			}
		case lua.HookCall:
			// Increment call depth and check recursion limit
			callDepth++
			if callDepth > recursionLimit {
				L.RaiseError("recursion limit exceeded (max %d)", recursionLimit)
			}
		case lua.HookReturn:
			// Decrement call depth when returning from a function
			if callDepth > 0 {
				callDepth--
			}
		}
		return 0 // Indicate no stack modifications
	}, lua.HookCount|lua.HookCall|lua.HookReturn, hookInstructionCount)

	// Load and execute the script to define the function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(result.(lua.LNumber)), nil
}

// Example usage
func main() {
	script := `
	function calculate_final_price(ctx)
		-- Apply 10% discount for VIP users (tier 2)
		if ctx.user_tier >= 2 then
			return ctx.base_price * 0.9
		else
			return ctx.base_price
		end
	end
	`
	ctx := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}
	price, err := ExecutePricingScript(script, ctx)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Final price: %.2f\n", price) // Should output 90.00
}

