package main

import (
	"context"
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context, with security restrictions in place.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a restricted Lua state with security controls
	L := lua.NewState(lua.Options{
		SkipOpenLibs: true, // Disable all standard libraries to prevent dangerous operations
		MemoryLimit:  10 * 1024 * 1024, // 10MB memory limit to prevent excessive memory usage
	})
	defer L.Close()

	// Set up timeout handling to prevent infinite loops or long-running scripts
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Install hook to enforce timeout - triggers every 1000 instructions
	L.SetHook(func(L *lua.LState, ar *lua.Debug) {
		select {
		case <-ctxTimeout.Done():
			L.RaiseError("script execution timed out after 5 seconds")
		default:
		}
	}, lua.HookCount, 1000)

	// Load and execute the script (with security restrictions active)
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Verify the required function exists and is a function type
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table (safe, since we control the input)
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the pricing function with protection against runtime errors
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Retrieve and validate the result
	result := L.Get(-1)
	L.Pop(1) // Clean up the stack

	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a valid number")
	}

	return float64(result.(lua.LNumber)), nil
}

